#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#define MAXN 10000
#define MAXM 30000

// Define the structure for a node
typedef struct Node {
    int x, y;
    struct Node* next;
} Node;

// Define the structure for an edge
typedef struct Edge {
    int u, v;
    struct Edge* next;
} Edge;

// Function to add an edge to the graph
void addEdge(Edge** edges, int u, int v) {
    Edge* newEdge = (Edge*)malloc(sizeof(Edge));
    newEdge->u = u;
    newEdge->v = v;
    newEdge->next = edges[u];
    edges[u] = newEdge;
}

// Function to perform DFS
void dfs(int* visited, Edge** edges, int node, int* blossoms) {
    visited[node] = 1;
    Edge* temp = edges[node];
    while (temp != NULL) {
        if (!visited[temp->v]) {
            dfs(visited, edges, temp->v, blossoms);
        }
        temp = temp->next;
    }
}

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N, M;
        scanf("%d %d", &N, &M);
        Node* nodes = (Node*)malloc(N * sizeof(Node));
        Edge** edges = (Edge**)malloc(N * sizeof(Edge*));
        for (int i = 0; i < N; i++) {
            edges[i] = NULL;
        }
        for (int i = 0; i < N; i++) {
            scanf("%d %d", &nodes[i].x, &nodes[i].y);
        }
        for (int i = 0; i < M; i++) {
            int u, v;
            scanf("%d %d", &u, &v);
            addEdge(edges, u, v);
        }
        int* visited = (int*)malloc(N * sizeof(int));
        int* blossoms = (int*)malloc(M * sizeof(int));
        for (int i = 0; i < N; i++) {
            visited[i] = 0;
        }
        for (int i = 0; i < M; i++) {
            blossoms[i] = 0;
        }
        dfs(visited, edges, 0, blossoms);
        for (int i = 0; i < M; i++) {
            printf("%d ", blossoms[i]);
        }
        printf("\n");
    }
    return 0;
}

