using namespace std;

// Define the structure for a node
struct Node {
    int x, y;
};

// Define the structure for an edge
struct Edge {
    int u, v;
};

// Function to add an edge to the graph
void addEdge(vector<vector<int>>& edges, int u, int v) {
    edges[u].push_back(v);
}

// Function to perform DFS
void dfs(vector<bool>& visited, vector<vector<int>>& edges, int node, vector<int>& blossoms) {
    visited[node] = true;
    for (int i = 0; i < edges[node].size(); i++) {
        if (!visited[edges[node][i]]) {
            dfs(visited, edges, edges[node][i], blossoms);
        }
    }
}

int main() {
    int T;
    cin >> T;
    while (T--) {
        int N, M;
        cin >> N >> M;
        vector<Node> nodes(N);
        vector<vector<int>> edges(N);
        for (int i = 0; i < N; i++) {
            cin >> nodes[i].x >> nodes[i].y;
        }
        for (int i = 0; i < M; i++) {
            int u, v;
            cin >> u >> v;
            addEdge(edges, u, v);
        }
        vector<bool> visited(N, false);
        vector<int> blossoms(M, 0);
        dfs(visited, edges, 0, blossoms);
        for (int i = 0; i < M; i++) {
            cout << blossoms[i] << " ";
        }
        cout << endl;
    }
    return 0;
}

