import java.util.Scanner;
import java.util.ArrayList;

public class Main {
    // Define the structure for a node
    static class Node {
        int x, y;
    }

    // Define the structure for an edge
    static class Edge {
        int u, v;
    }

    // Function to add an edge to the graph
    public static void addEdge(ArrayList<ArrayList<Integer>> edges, int u, int v) {
        edges.get(u).add(v);
    }

    // Function to perform DFS
    public static void dfs(boolean[] visited, ArrayList<ArrayList<Integer>> edges, int node, int[] blossoms) {
        visited[node] = true;
        for (int i = 0; i < edges.get(node).size(); i++) {
            if (!visited[edges.get(node).get(i)]) {
                dfs(visited, edges, edges.get(node).get(i), blossoms);
            }
        }
    }

    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        int T = scanner.nextInt();
        while (T-- > 0) {
            int N = scanner.nextInt();
            int M = scanner.nextInt();
            Node[] nodes = new Node[N];
            ArrayList<ArrayList<Integer>> edges = new ArrayList<>();
            for (int i = 0; i < N; i++) {
                nodes[i] = new Node();
                scanner.nextInt();
                scanner.nextInt();
                edges.add(new ArrayList<>());
            }
            for (int i = 0; i < M; i++) {
                int u = scanner.nextInt();
                int v = scanner.nextInt();
                addEdge(edges, u, v);
            }
            boolean[] visited = new boolean[N];
            int[] blossoms = new int[M];
            dfs(visited, edges, 0, blossoms);
            for (int i = 0; i < M; i++) {
                System.out.print(blossoms[i] + " ");
            }
            System.out.println();
        }
    }
}

